class Solution {
public:
    vector<bool> canMakePalindromeQueries(string s, vector<vector<int>>& queries) {
        int n = s.size();
        vector<int> diff(n / 2, 0);
        for (int i = 0; i < n / 2; ++i) {
            diff[i] = (s[i] == s[n - 1 - i]) ? 0 : 1;
            if (i > 0) diff[i] += diff[i - 1];
        }

        vector<bool> ans;
        for (auto& q : queries) {
            int l1 = q[0], r1 = q[1], l2 = q[2], r2 = q[3];
            int count1 = countCharacters(s, l1, r1);
            int count2 = countCharacters(s, l2, r2);
            bool valid = isValid(s, l1, r1, l2, r2, diff);
            bool match = isMatch(count1, count2);
            ans.push_back(valid && match);
        }
        return ans;
    }

    int countCharacters(const string& s, int l, int r) {
        vector<int> count(26, 0);
        for (int i = l; i <= r; ++i) {
            count[s[i] - 'a']++;
        }
        return accumulate(count.begin(), count.end(), 0);
    }

    bool isValid(const string& s, int l1, int r1, int l2, int r2, const vector<int>& diff) {
        int left = l1, right = s.size() - 1 - r2;
        int diff_count = (left > 0) ? diff[left - 1] : 0;
        diff_count = diff[r2 - (s.size() - 1 - left)] - diff_count;
        return diff_count == 0;
    }

    bool isMatch(int count1, int count2) {
        vector<int> freq1(26, 0), freq2(26, 0);
        string s = "abcdefghijklmnopqrstuvwxyz";
        for (char c : s) {
            freq1[c - 'a'] = count(s.begin(), s.begin() + count1, c);
            freq2[c - 'a'] = count(s.begin() + count1, s.end(), c);
        }
        for (int i = 0; i < 26; ++i) {
            if (freq1[i] != freq2[i]) return false;
        }
        return true;
    }
};
